#include<bits/stdc++.h>
using namespace std;
long long n,k,a[1000005];
bool f(long long x){
	long long sum=0;
	for(int i=1;i<=n;i++)sum+=a[i]/x;
	return sum>=k;
}
int main(void){
	cin>>n>>k;
	for(int i=1;i<=n;i++)cin>>a[i];
	long long l=0,r=100000001,mid;
	while(l<r-1){
		mid=(l+r)/2;
		if(f(mid))l=mid;
		else r=mid;
	}
	cout<<l;
	return false;
}
